/// manage a frame which has the same lifecycle as the tracker
#[derive(Clone)]
pub struct FrameTracker {
    pub paddr: PhysAddr,
}

impl FrameTracker {
    pub fn new(paddr: PhysAddr) -> Self {
        // page cleaning
        paddr.clear_len(PAGE_SIZE);
        Self { paddr }
    }
}

impl Debug for FrameTracker {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("FrameTracker:PA={:?}", self.paddr))
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        // trace!("drop frame tracker: {:?}", self.paddr);
        frame_dealloc(self.paddr);
    }
}

pub static FRAME_ALLOCATOR: MutexNoIrq<FrameAllocator> = MutexNoIrq::new(FrameAllocator::new());

pub fn add_frames_range(mm_start: usize, mm_end: usize) {
    unsafe {
        core::slice::from_raw_parts_mut(
            pa!(mm_start).get_mut_ptr::<u128>(),
            (mm_end - mm_start) / size_of::<u128>(),
        )
        .fill(0);
    }
    let start = (mm_start + 0xfff) / PAGE_SIZE;
    FRAME_ALLOCATOR.lock().add_frame(start, mm_end / PAGE_SIZE);
}

pub fn frame_alloc() -> Option<Arc<FrameTracker>> {
    let frame_num = FRAME_ALLOCATOR.lock().alloc(1)?;
    let paddr = pa!(frame_num * PAGE_SIZE);

    if paddr.raw() == 0 {
        error!(
            "[frame_alloc] ERROR: Allocated frame number {} results in physical address 0x0!",
            frame_num
        );
        error!("[frame_alloc] This should not happen - frame 0 should be reserved!");
        return None;
    }

    // debug!(
    //     "[frame_alloc] Allocated frame {} -> paddr={:#x}",
    //     frame_num,
    //     paddr.raw()
    // );
    let tracker = FrameTracker::new(paddr);
    tracker.paddr.clear_len(PAGE_SIZE);
    Some(Arc::new(tracker))
}

pub fn frames_alloc(count: usize) -> Option<Vec<Arc<FrameTracker>>> {
    let start_frame_num = FRAME_ALLOCATOR.lock().alloc(count)?;
    let start_paddr = pa!(start_frame_num * PAGE_SIZE);

    if start_paddr.raw() == 0 {
        // error!("[frames_alloc] ERROR: Allocated starting frame number {} results in physical address 0x0!", start_frame_num);
        // error!("[frames_alloc] This should not happen - frame 0 should be reserved!");
        return None;
    }

    // debug!(
    //     "[frames_alloc] Allocated {} frames starting from frame {} -> paddr={:#x}",
    //     count,
    //     start_frame_num,
    //     start_paddr.raw()
    // );

    let ret = (0..count)
        .into_iter()
        .map(|idx| {
            let paddr = start_paddr + idx * PAGE_SIZE;
            // debug!("[frames_alloc] Frame[{}]: paddr={:#x}", idx, paddr.raw());
            paddr
        })
        .map(FrameTracker::new)
        .inspect(|x| x.paddr.clear_len(PAGE_SIZE))
        .map(Arc::new)
        .collect();
    Some(ret)
}

pub fn frame_alloc_persist() -> Option<PhysAddr> {
    let frame_num = FRAME_ALLOCATOR.lock().alloc(1)?;
    let paddr = pa!(frame_num * PAGE_SIZE);

    if paddr.raw() == 0 {
        error!("[frame_alloc_persist] ERROR: Allocated frame number {} results in physical address 0x0!", frame_num);
        error!("[frame_alloc_persist] This should not happen - frame 0 should be reserved!");
        return None;
    }

    // debug!(
    //     "[frame_alloc_persist] Allocated frame {} -> paddr={:#x}",
    //     frame_num,
    //     paddr.raw()
    // );
    paddr.clear_len(PAGE_SIZE);
    Some(paddr)
}

pub fn frame_dealloc(paddr: PhysAddr) {
    FRAME_ALLOCATOR.lock().dealloc(paddr.raw() / PAGE_SIZE, 1);
}

#[allow(unused)]
/// a simple test for frame allocator
pub fn frame_allocator_test() {
    let mut v: Vec<Arc<FrameTracker>> = Vec::new();
    for i in 0..5 {
        let frame = frame_alloc().unwrap();
        debug!("[frame_allocator_test] Allocated frame: {:?}", frame);
        v.push(frame);
    }
    v.clear();
    for i in 0..5 {
        let frame = frame_alloc().unwrap();
        debug!("[frame_allocator_test] Re-allocated frame: {:?}", frame);
        v.push(frame);
    }
    drop(v);
    info!("[frame_allocator_test] Frame allocator test passed!");
}

use crate::config::KERNEL_HEAP_SIZE;
