pub struct MemorySet {
    pub inner: UPSafeCell<MemorySetInner>,
}

impl MemorySet {
    pub fn new(memory_set: MemorySetInner) -> Self {
        Self {
            inner: unsafe { UPSafeCell::new(memory_set) },
        }
    }
    #[inline(always)]
    pub fn inner_exclusive_access(&self) -> RefMut<'_, MemorySetInner> {
        self.inner.exclusive_access()
    }
    #[inline(always)]
    pub fn token(&self) -> PageTable {
        self.inner_exclusive_access().token()
    }
    #[inline(always)]
    pub fn lazy_page_fault(&self, vaddr: VirtAddr, trap_type: TrapType) -> bool {
        self.inner_exclusive_access()
            .lazy_page_fault(vaddr, trap_type)
    }
    #[inline(always)]
    pub fn cow_page_fault(&self, vaddr: VirtAddr, trap_type: TrapType) -> bool {
        self.inner_exclusive_access()
            .cow_page_fault(vaddr, trap_type)
    }
    // #[inline(always)]
    // pub fn push(&self, map_area: MapArea, offset: usize, data: Option<&[u8]>) {
    //     self.inner_exclusive_access().push(map_area, offset, data)
    // }
    #[inline(always)]
    pub fn mmap(
        &self,
        addr: usize,
        len: usize,
        map_perm: MapPermission,
        flags: MmapFlags,
        file: Option<Arc<OSInode>>,
        off: usize,
    ) -> usize {
        self.inner_exclusive_access()
            .mmap(addr, len, map_perm, flags, file, off)
    }
    #[inline(always)]
    pub fn munmap(&self, addr: VirtAddr, len: usize) -> SyscallRet {
        self.inner_exclusive_access().munmap(addr, len)
    }
    /// Include sections in elf and trampoline and TrapContext and user stack,
    /// also returns user_sp and entry point.
    #[inline(always)]
    pub fn from_existed_user(user_space: &MemorySet) -> Self {
        let inner = MemorySetInner::from_existed_user(&user_space.inner_exclusive_access());
        Self::new(inner)
    }
    ///浅拷贝
    pub fn shallow_clone(&self) -> Self {
        let inner = self.inner_exclusive_access().shallow_clone();
        Self::new(inner)
    }
    #[inline(always)]
    pub fn shm(
        &self,
        addr: usize,
        size: usize,
        map_perm: MapPermission,
        pages: Vec<Arc<FrameTracker>>,
    ) -> usize {
        self.inner_exclusive_access()
            .shm(addr, size, map_perm, pages)
    }
    #[inline(always)]
    pub fn translate(&self, vaddr: VirtAddr) -> Option<(PhysAddr, MappingFlags)> {
        self.inner_exclusive_access().translate(vaddr)
    }
    #[inline(always)]
    pub fn lazy_insert_framed_area_with_hint(
        &self,
        hint: usize,
        size: usize,
        map_perm: MapPermission,
        area_type: MapAreaType,
    ) -> (usize, usize) {
        self.inner_exclusive_access()
            .lazy_insert_framed_area_with_hint(hint, size, map_perm, area_type)
    }
    #[inline(always)]
    pub fn recycle_data_pages(&self) {
        self.inner_exclusive_access().recycle_data_pages()
    }
    #[inline(always)]
    pub fn mprotect(&self, start_addr: VirtAddr, end_addr: VirtAddr, map_perm: MapPermission) {
        self.inner_exclusive_access()
            .mprotect(start_addr, end_addr, map_perm)
    }
}

