            warn!("[lazy_page_fault] vaddr, paddr:{:#x}", paddr.raw());
            return false;
        }
        if let Some(area) = self
            .areas
            .iter_mut()
            .filter(|area| area.area_type == MapAreaType::Mmap)
            .find(|area| {
                let (start, end) = area.vaddr_range.range();
                start <= vaddr && vaddr < end
            })
        {
            match trap_type {
                TrapType::LoadPageFault(_) => {
                    mmap_read_page_fault(vaddr.into(), &mut self.page_table, area);
                }
                TrapType::StorePageFault(_) => {
                    mmap_write_page_fault(vaddr.into(), &mut self.page_table, area);
                }
                _ => {
                    warn!("unexpected trap_type: {:?}", trap_type);
                    return false;
                }
            }
            return true;
        }
        if let Some(area) = self
            .areas
            .iter_mut()
            .filter(|area| {
                area.area_type == MapAreaType::Brk || area.area_type == MapAreaType::Stack
            })
            .find(|area| {
                let (start, end) = area.vaddr_range.range();
                start <= vaddr && vaddr < end
            })
        {
            area.map_one(&self.page_table, vaddr);
