pub struct MapArea {
    pub vaddr_range: VAddrRange,
    pub data_frames: BTreeMap<VirtAddr, Arc<FrameTracker>>,
    map_type: MapType,
    pub map_perm: MapPermission,
    pub area_type: MapAreaType,
    pub mmap_file: MmapFile,
    pub mmap_flags: MmapFlags,
    pub groupid: usize,
}

impl Clone for MapArea {
    fn clone(&self) -> Self {
        let new_area = Self {
            vaddr_range: self.vaddr_range.clone(),
            data_frames: self.data_frames.clone(),
            map_type: self.map_type,
            map_perm: self.map_perm,
            area_type: self.area_type,
            mmap_file: self.mmap_file.clone(),
            mmap_flags: self.mmap_flags,
            groupid: self.groupid,
        };

        // 自动维护引用计数
        if new_area.groupid != 0 {
            GROUP_SHARE.lock().add_area(new_area.groupid);
        }

        new_area
    }
}

impl MapArea {
    pub fn new(
        start_va: VirtAddr,
        end_va: VirtAddr,
        map_type: MapType,
        map_perm: MapPermission,
        area_type: MapAreaType,
    ) -> Self {
        let start_vpn: VirtAddr = start_va.floor();
        let end_vpn: VirtAddr = end_va.ceil();
        Self {
            vaddr_range: VAddrRange::new(start_vpn, end_vpn),
            data_frames: BTreeMap::new(),
            map_type,
            map_perm,
            area_type,
            mmap_file: MmapFile::empty(),
            mmap_flags: MmapFlags::empty(),
            groupid: 0,
        }
    }
    pub fn from_another(another: &MapArea) -> Self {
        let new_area = Self {
            vaddr_range: VAddrRange::new(
                another.vaddr_range.get_start(),
                another.vaddr_range.get_end(),
            ),
            data_frames: BTreeMap::new(),
            map_type: another.map_type,
            map_perm: another.map_perm,
            area_type: another.area_type,
            mmap_file: another.mmap_file.clone(),
            mmap_flags: another.mmap_flags,
            groupid: another.groupid,
        };

        // 自动维护引用计数
        if new_area.groupid != 0 {
            GROUP_SHARE.lock().add_area(new_area.groupid);
        }

        new_area
    }

    pub fn new_mmap(
        start_va: VirtAddr,
        end_va: VirtAddr,
        map_type: MapType,
        map_perm: MapPermission,
        area_type: MapAreaType,
        file: Option<Arc<OSInode>>,
        offset: usize,
        mmap_flags: MmapFlags,
    ) -> Self {
        let start_vaddr: VirtAddr = start_va.floor();
        let end_vaddr: VirtAddr = end_va.ceil();
        let groupid = GROUP_SHARE.lock().alloc_id();
        GROUP_SHARE.lock().add_area(groupid);
        Self {
            vaddr_range: VAddrRange::new(start_vaddr, end_vaddr),
            data_frames: BTreeMap::new(),
            map_type,
            map_perm,
            area_type,
            mmap_file: MmapFile::new(file, offset),
            mmap_flags,
            groupid,
        }
    }
    pub fn map_one(&mut self, page_table: &Arc<PageTableWrapper>, va: VirtAddr) {
        let p_tracker = frame_alloc().expect("can't allocate frame");
        page_table.map_page(
            va,
            p_tracker.paddr,
            self.map_perm.into(),
            MappingSize::Page4KB,
        );
        self.data_frames.insert(va, p_tracker);
    }

    pub fn unmap_one(&mut self, page_table: &Arc<PageTableWrapper>, va: VirtAddr) {
        self.data_frames.remove(&va);
        page_table.unmap_page(va);
    }

    pub fn map(&mut self, page_table: &Arc<PageTableWrapper>) {
        trace!("MapArea::map");
        for vaddr in self.vaddr_range {
            // self.map_one(page_table, vpn);
            self.map_one(page_table, vaddr);
        }
    }
    pub fn map_given_frames(
        &mut self,
        page_table: &Arc<PageTableWrapper>,
        frames: Vec<Arc<FrameTracker>>,
    ) {
        for (va, frame) in self.vaddr_range.clone().into_iter().zip(frames.into_iter()) {
            page_table.map_page(va, frame.paddr, self.map_perm.into(), MappingSize::Page4KB);
            self.data_frames.insert(va, frame);
        }
    }
    /// Unmap page area
    #[allow(unused)]
    pub fn unmap(&mut self, page_table: &Arc<PageTableWrapper>) {
        trace!("MapArea::unmap");
        for vaddr in self.vaddr_range {
            self.unmap_one(page_table, vaddr);
        }
    }

    /// data: start-aligned but maybe with shorter length
    /// assume that all frames were cleared before
    pub fn copy_data(&mut self, page_table: &Arc<PageTableWrapper>, offset: usize, data: &[u8]) {
        trace!("MapArea::copy_data");
        assert_eq!(self.map_type, MapType::Framed);
        let mut start: usize = 0;
        let mut pg_offset = offset;
        let mut curr_vaddr = self.vaddr_range.get_start().floor();
        debug!("offset:{},start vaddr:{}", offset, curr_vaddr);
        let len = data.len();
        loop {
            let src = &data[start..len.min(start + PAGE_SIZE - pg_offset)];
            let dst = &mut page_table
                .translate((curr_vaddr + pg_offset).into())
                .unwrap()
                .0
                .slice_mut_with_len(src.len());
            dst.copy_from_slice(src);
