    }
    pub fn alloc_fd(&mut self) -> usize {
        self.fd_table.alloc_fd()
    }
    pub fn get_file(&self, fd: usize) -> Option<FileDescriptor> {
        self.fd_table.get_file(fd)
    }
    pub fn get_abs_path(&self, dirfd: isize, path: &str) -> Result<String, SysErrNo> {
        trace!("into get abs path");
        if is_abs_path(path) {
            Ok(get_abs_path("/", path))
        } else if dirfd != -100 {
            //ATFDCWD=-100
            let dirfd = dirfd as usize;
            let base_path = self.fd_table.get_file(dirfd).unwrap().file()?.inode.path();
            if path.is_empty() {
                Ok(base_path)
            } else {
                Ok(get_abs_path(&base_path, path))
            }
        } else {
            Ok(get_abs_path(&self.fsinfo.get_cwd(), path))
        }
    }
    /// 分配用户空间资源
    pub fn alloc_user_res(&mut self) {
        debug!(
            "[alloc_user_res] called, USER_STACK_TOP={:#x}, USER_STACK_SIZE={:#x}",
            USER_STACK_TOP, USER_STACK_SIZE
        );
        let (user_stack_bottom, user_stack_top) =
            self.memory_set.lazy_insert_framed_area_with_hint(
                USER_STACK_TOP,
                USER_STACK_SIZE,
                MapPermission::R | MapPermission::W | MapPermission::U,
                MapAreaType::Stack,
            );
        let user_stack_range = VAddrRange::new(user_stack_bottom.into(), user_stack_top.into());
        info!("[alloc_user_res] user_stack_range={:?}", user_stack_range);
        self.user_stack_top = user_stack_top;

        // 获取内存集的可变引用来操作areas
        let mut memory_set_inner = self.memory_set.inner_exclusive_access();
        let page_table = memory_set_inner.page_table.clone();
        let area = memory_set_inner
            .areas
            .iter_mut()
            .find(|area| area.vaddr_range.range() == user_stack_range.range())
            .unwrap();
        // 为用户栈预先分配几页，从栈顶开始向下分配
        for i in 1..=PRE_ALLOC_PAGES {
            let vaddr = VirtAddr::new(area.vaddr_range.get_end().raw() - i * PAGE_SIZE);
            // 检查该虚拟地址是否已经映射
            if page_table.translate(vaddr).is_none() {
                // 使用map_one分配物理页并建立映射
                area.map_one(&page_table, vaddr);
            }
        }
    }
