pub fn sys_getcwd(buf: *mut u8, len: usize) -> SyscallRet {
    trace!(
        "[sys_getcwd] called with buf=0x{:x} (output pointer for cwd string), len={}",
        buf as usize,
        len
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();

    // 获取当前工作目录
    let cwd = inner.fsinfo.get_cwd();
    drop(inner);
    drop(task);
    debug!("[sys_getcwd] current working directory: {}", cwd);

    // 检查缓冲区长度是否足够
    if cwd.len() + 1 > len {
        warn!(
            "[sys_getcwd] buffer too small: need {}, got {}",
            cwd.len() + 1,
            len
        );
        return Err(SysErrNo::ERANGE); // 缓冲区不足
    }

    let mut user_buf = UserBuffer::new(translated_byte_buffer(&token, buf, len));

    user_buf.write(cwd.as_bytes());
    //user_buf.write(&[0]); // 写入字符串结束符 '\0'

    Ok(cwd.len()) // 返回写入的字节数（不包括 '\0'）
}

pub fn sys_dup(fd: usize) -> SyscallRet {
    trace!("[sys_dup] called with fd={}", fd);
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let file = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    let new_fd = inner.alloc_fd();
    inner.fd_table.set(new_fd, file);
    Ok(new_fd)
}

pub fn sys_dup3(old_fd: usize, new_fd: usize, flags: u32) -> SyscallRet {
    let flags = OpenFlags::from_bits(flags).unwrap();
    trace!(
        "[sys_dup3] called with old_fd={}, new_fd={}, flags={:?}",
        old_fd,
        new_fd,
        flags
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if old_fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let mut file = inner.fd_table.get_file(old_fd).ok_or(SysErrNo::EBADF)?;
    if old_fd == new_fd {
        debug!("[sys_dup3] old_fd and new_fd are the same");
        return Ok(new_fd);
    }
    if new_fd >= inner.fd_table.len() {
        inner.fd_table.resize(new_fd + 1);
    }
    // 如果 new_fd 已经被占用，先关闭它
    if inner.fd_table.get_file(new_fd).is_some() {
        debug!("[sys_dup3] closing existing new_fd {}", new_fd);
        inner.fd_table.remove(new_fd);
    }
    file.set_flags(flags);
    inner.fd_table.set(new_fd, file);
    Ok(new_fd)
}

pub fn sys_fcntl(fd: usize, cmd: usize, arg: usize) -> SyscallRet {
    trace!(
        "[sys_fcntl] called with fd={}, cmd={:?}({}), arg={}",
        fd,
        fcntl_cmd_name(cmd),
        cmd,
        arg
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let mut file = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    match cmd {
        F_DUPFD => {
            let new_fd = inner.fd_table.alloc_fd_larger(arg)?;
            file.unset_cloexec();
            inner.fd_table.set(new_fd, file);
            // task_inner.fs_info.insert_with_glue(fd, fd_new);
            Ok(new_fd)
        }
        F_DUPFD_CLOEXEC => {
            let new_fd = inner.fd_table.alloc_fd_larger(arg)?;
            file.set_cloexec();
            inner.fd_table.set(new_fd, file);
            // task_inner.fs_info.insert_with_glue(fd, fd_new);
            Ok(new_fd)
        }
        F_GETFD => Ok(if file.cloexec() { 1 } else { 0 }),
        F_SETFD => {
            if arg & 1 != 0 {
                file.set_cloexec();
            } else {
                file.unset_cloexec();
            }
            Ok(0)
        }
        F_GETFL => Ok(file.get_flags().bits() as usize),
        _ => Err(SysErrNo::EINVAL),
    }
}

