pub fn sys_mkdirat(dirfd: isize, path: *const u8, _mode: usize) -> SyscallRet {
    trace!("[sys_mkdirat] called with dirfd={}, path={:p}", dirfd, path);
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let path = translated_str(token, path);
    debug!("[sys_mkdirat] path: {}", path);
    let abs_path = inner.get_abs_path(dirfd, &path)?;
    debug!("[sys_mkdirat] absolute path: {}", abs_path);
    drop(inner);
    drop(task);
    let created = open(
        abs_path.as_str(),
        OpenFlags::O_DIRECTORY | OpenFlags::O_CREATE | OpenFlags::O_RDWR,
    );
    if created.is_ok() {
        Ok(0)
    } else {
        Err(SysErrNo::EIO)
    }
}

