pub fn sys_mmap(
    start: usize,
    len: usize,
    prot: usize,
    flags: usize,
    fd: usize,
    offset: usize,
) -> SyscallRet {
    trace!("[sys_mmap] Enter: start=0x{:x}, len=0x{:x}, prot=0x{:x}, flags=0x{:x}, fd={}, offset=0x{:x}",
           start, len, prot, flags, fd, offset);
    let mmap_prot = MapPermission::from(MmapProt::from_bits(prot as u32).unwrap());
    let flags = MmapFlags::from_bits(flags as u32).unwrap();
    if flags.contains(MmapFlags::MAP_FIXED) && start == 0 {
        return Err(SysErrNo::EPERM);
    }
    let len = page_round_up(len);
    let task = current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    if fd == usize::MAX {
        if !flags.contains(MmapFlags::MAP_ANONYMOUS) {
            return Err(SysErrNo::EBADF);
        }
        let rv = task_inner
            .memory_set
            .mmap(start, len, mmap_prot, flags, None, offset);
        return Ok(rv);
    }
    debug!("[sys_mmap] Mapping file descriptor: {}", fd);
    if let Some(file) = &task_inner.fd_table.get_file(fd) {
        let file = file.file().unwrap();
        let addr = task_inner
            .memory_set
            .mmap(start, len, mmap_prot, flags, Some(file), offset);
        info!("[sys_mmap] Successfully mapped at: 0x{:x}", addr);
        Ok(addr)
    } else {
        warn!("[sys_mmap] Invalid file descriptor: {}", fd);
        Err(SysErrNo::EPERM)
    }
}

pub fn sys_mprotect(addr: usize, len: usize, prot: u32) -> SyscallRet {
    trace!(
        "[sys_mprotect] Enter: addr=0x{:x}, len=0x{:x}, prot=0x{:x}",
        addr,
        len,
        prot
    );

    if (addr % PAGE_SIZE != 0) || (len % PAGE_SIZE != 0) {
        return Err(SysErrNo::EINVAL);
    } //检查页面对齐

    let map_perm: MapPermission = MmapProt::from_bits(prot).unwrap().into();

    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    let memory_set = &mut inner.memory_set;
    let start_vpn = VirtAddr::from(addr).floor();
    let end_vpn = VirtAddr::from(addr + len).ceil();

    memory_set.mprotect(start_vpn, end_vpn, map_perm);
    Ok(0)
}

