pub fn sys_rt_sigaction(signo: usize, act: *const u8, oldact: *mut u8) -> SyscallRet {
    trace!(
        "[sys_rt_sigaction] Enter: signo={}, act=0x{:x}, oldact=0x{:x} (output pointer for SigAction)",
        signo,
        act as usize,
        oldact as usize,
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();
    if oldact as usize != 0 {
        let old_action = inner.sig_table.action(signo).act;
        // *translated_refmut::<SigAction>(token, oldact as *mut SigAction) = old_action;
        put_data(token, oldact as *mut SigAction, old_action);
        debug!(
            "[sys_rt_sigaction] Retrieved old signal action for signal {}",
            signo
        );
    }
    if act as usize != 0 {
        let new_act: SigAction = get_data(token, act as *const SigAction);
        debug!(
            "[sys_rt_sigaction] Setting new signal action for signal {}",
            signo
        );
        Ok(inner.sig_table.set(signo, new_act) as usize)
    } else {
        Ok(0)
    }
}

pub fn sys_sig_proc_mask(how: u32, set: *const u8, old_set: *mut u8) -> SyscallRet {
    trace!(
        "[sys_sig_proc_mask] Enter: how={}, set=0x{:x}, old_set=0x{:x} (output pointer for SignalFlags)",
        how,
        set as usize,
        old_set as usize
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if old_set as usize != 0 {
        let old_mask = inner.signal_mask;
        put_data(token, old_set as *mut SignalFlags, old_mask);
        // debug!("[sys_sig_proc_mask] Retrieved old signal mask");
    }
    if set as usize != 0 {
        let new_mask: SignalFlags = get_data(token, set as *const SignalFlags);
        // debug!(
        //     "[sys_sig_proc_mask] Setting new signal mask: {:?}",
        //     new_mask
        // );
        match SignalMaskFlag::from_bits(how).unwrap() {
            SignalMaskFlag::SIG_BLOCK => {
                inner.signal_mask |= new_mask;
                debug!(
                    "[sys_sig_proc_mask] Blocked signals: {:?}",
                    inner.signal_mask
                );
            }
            SignalMaskFlag::SIG_UNBLOCK => {
                inner.signal_mask &= !new_mask;
                debug!(
                    "[sys_sig_proc_mask] Unblocked signals: {:?}",
                    inner.signal_mask
                );
            }
            SignalMaskFlag::SIG_SETMASK => {
                inner.signal_mask = new_mask;
                debug!(
                    "[sys_sig_proc_mask] Set new signal mask: {:?}",
                    inner.signal_mask
                );
            }
            _ => {
                warn!("[sys_sig_proc_mask] Unknown how value: {}", how);
            }
        }
        Ok(0)
    } else {
        Err(SysErrNo::EINVAL)
    }
}

