/// 表示进程中一个被打开的常规文件或目录
pub struct OSInode {
    readable: bool, // 该文件是否允许通过 sys_read 进行读
    writable: bool, // 该文件是否允许通过 sys_write 进行写
    pub inode: Arc<Ext4Inode>,
    inner: Mutex<OSInodeInner>,
}

pub struct OSInodeInner {
    offset: usize, // 偏移量
}

impl OSInode {
    pub fn new(readable: bool, writable: bool, inode: Arc<Ext4Inode>) -> Self {
        Self {
            readable,
            writable,
            inode,
            inner: Mutex::new(OSInodeInner { offset: 0 }),
        }
    }

    pub fn is_dir(&self) -> bool {
        self.inode.types() == InodeType::Dir
    }

    pub fn name(&self) -> String {
        self.inode.path()
    }

    pub fn lseek(&self, offset: isize, whence: u32) -> SyscallRet {
        trace!(
            "[lseek] Seeking in file: {}, offset: {}, whence: {}",
            self.name(),
            offset,
            whence
        );
        let mut inner = self.inner.lock();
        debug!("old offset: {}", inner.offset);
        match whence {
            SEEK_SET => {
                if offset < 0 {
                    return Err(SysErrNo::EINVAL);
                }
                inner.offset = offset as usize;
            }
            SEEK_CUR => {
                let newoff = inner.offset as isize + offset;
                if newoff < 0 {
                    return Err(SysErrNo::EINVAL);
                }
                inner.offset = newoff as usize;
            }
            SEEK_END => {
                let newoff = self.inode.size() as isize + offset;
                if newoff < 0 {
                    return Err(SysErrNo::EINVAL);
                }
                inner.offset = newoff as usize;
            }
            _ => return Err(SysErrNo::EINVAL),
        }
        debug!("new offset: {}", inner.offset);
        Ok(inner.offset)
    }

    pub fn fstat(&self) -> Kstat {
        self.inode.fstat()
    }

    pub fn truncate(&self, size: usize) -> SyscallRet {
        if !self.writable {
            return Err(SysErrNo::EBADF);
        }
        self.inode.truncate(size)
    }
    pub fn size(&self) -> usize {
        self.inode.size()
    }
}

