// 定义一份打开文件的标志
bitflags! {
    pub struct OpenFlags: u32 {
        // 访问模式标志
        const O_RDONLY    = 0;             // 只读模式
        const O_WRONLY    = 1 << 0;        // 只写模式
        const O_RDWR      = 1 << 1;        // 读写模式
        const O_ACCMODE   = 0b11;          // 访问模式掩码 (RDONLY|WRONLY|RDWR)

        // 文件创建/行为标志
        const O_CREATE     = 1 << 6;        // 文件不存在时创建
        const O_EXCL      = 1 << 7;        // 与O_CREATE配合使用，文件必须不存在
        const O_NOCTTY    = 1 << 8;        // 不分配控制终端
        const O_TRUNC     = 1 << 9;        // 打开时清空文件内容
        const O_APPEND    = 1 << 10;       // 追加写入模式
        const O_NONBLOCK  = 1 << 11;       // 非阻塞模式
        const O_DSYNC     = 1 << 12;       // 数据同步写入 (POSIX)

        // 高级文件操作标志
        const O_ASYNC     = 1 << 13;       // 信号驱动I/O
        const O_DIRECT    = 1 << 14;       // 直接磁盘访问（无缓冲）
        const O_LARGEFILE = 1 << 15;       // 支持大文件（>2GB）
        const O_DIRECTORY = 1 << 16;       // 必须为目录
        const O_NOFOLLOW  = 1 << 17;       // 不追踪符号链接
        const O_NOATIME   = 1 << 18;       // 不更新访问时间
        const O_CLOEXEC   = 1 << 19;       // 执行时关闭文件描述符

        // 同步I/O标志 (复合值)
        const O_SYNC      = 1 << 20 | 1 << 15; // 文件/元数据同步写入
        const O_RSYNC     = 1 << 20 | 1 << 15; // 同步读取操作 (同O_SYNC)

        // 特殊文件标志
        const O_PATH      = 1 << 21;       // 获取目录句柄（不打开文件）
        const O_TMPFILE   = 1 << 22 | 1 << 16; // 创建未命名临时文件
    }
}

impl OpenFlags {
    pub fn read_write(&self) -> (bool, bool) {
        if self.is_empty() {
            (true, false)
        } else if self.contains(Self::O_WRONLY) {
            (false, true)
        } else {
            (true, true)
        }
    }
    pub fn node_type(&self) -> InodeType {
        if self.contains(OpenFlags::O_DIRECTORY) {
            InodeType::Dir
        } else {
            InodeType::File
        }
    }
}
