fn create_file(abs_path: &str, flags: OpenFlags) -> Option<Arc<OSInode>> {
    trace!(
        "[create_file] Creating file: path='{}', flags={:?}",
        abs_path,
        flags
    );
    // 一定能找到,因为除了RootInode外都有父结点
    let parent_dir = root_inode();
    let (readable, writable) = flags.read_write();
    let inode = match parent_dir.create(abs_path, flags.node_type()) {
        Ok(inode) => {
            debug!(
                "[create_file] Successfully created inode for: '{}'",
                abs_path
            );
            inode
        }
        Err(_) => {
            warn!("[create_file] Failed to create inode for: '{}'", abs_path);
            return None;
        }
    };
    insert_inode_idx(abs_path, inode.clone());
    // inode.fmode_set(mode);
    let osinode = OSInode::new(readable, writable, inode);
    info!("[create_file] Successfully created file: '{}'", abs_path);
    Some(Arc::new(osinode))
}

pub fn open(abs_path: &str, flags: OpenFlags) -> Result<FileClass, SysErrNo> {
    debug!("path is {}, flags is {:?}", &abs_path, flags);
    // 1. 先查虚拟文件注册表
    if let Some(vfile) = get_vfile(abs_path) {
        debug!("[open] found virtual file: {}", abs_path);
        // 对于虚拟文件，每次打开时重置偏移量
        vfile.set_offset(0);
        return Ok(FileClass::Abs(vfile));
    }
    // 2. 查找真实文件
