    pub fn alloc_fd(&self) -> usize {
        let mut inner = self.inner_exclusive_access();
        let soft_limit = inner.soft_limit;
        let mut files = &mut inner.files;

        if let Some(fd) = (0..files.len()).find(|fd| files[*fd].is_none()) {
            info!("Reusing fd: {}", fd);
            return fd;
        }
        if files.len() >= soft_limit {
            // 已达到软限制，无法分配新的文件描述符
            return usize::MAX; // 使用特殊值表示失败
        }
        files.push(None);
        files.len() - 1
    }
    pub fn alloc_fd_larger(&self, arg: usize) -> SyscallRet {
        let mut inner = self.inner_exclusive_access();
        let soft_limit = inner.soft_limit;
        let mut files = &mut inner.files;
        if arg > soft_limit {
            panic!("arg > soft limit");
            return Err(SysErrNo::EMFILE);
        }
        if files.len() < arg {
            files.resize(arg, None);
        }

        if let Some(fd) = (arg..files.len()).find(|fd| files[*fd].is_none()) {
            Ok(fd)
        } else {
            files.push(None);
            Ok(files.len() - 1)
        }
