pub struct SigAction {
    pub sa_handler: usize,        // 信号处理函数地址
    pub sa_flags: SigActionFlags, // 信号处理行为标志
    pub sa_restore: usize,        // 信号返回函数地址
    pub sa_mask: SignalFlags,     // 处理期间的临时信号掩码
}

impl SigAction {
    pub fn new(signo: usize) -> Self {
        let handle: usize = if signo == 0 {
            1
        } else {
            match SignalFlags::from_sig(signo).default_op() {
                SigOp::Continue | SigOp::Ignore => 1,
                SigOp::Stop => 1, // TODO: 添加Stop状态和相关函数
                SigOp::Terminate | SigOp::CoreDump => exit_current_and_run_next as usize,
            }
        };
        Self {
            sa_handler: handle,
            sa_flags: SigActionFlags::empty(),
            sa_restore: 0,
            sa_mask: SignalFlags::empty(),
        }
    }
    pub fn empty() -> Self {
        Self {
            sa_handler: 1,
            sa_flags: SigActionFlags::empty(),
            sa_restore: 0,
            sa_mask: SignalFlags::empty(),
        }
    }
}

