pub struct KSigAction {
    pub act: SigAction,
    customed: bool, // 是否为默认处理
}

impl KSigAction {
    pub fn new(signo: usize, customed: bool) -> Self {
        Self {
            act: SigAction::new(signo),
            customed: customed,
        }
    }
    pub fn ignore() -> Self {
        Self {
            act: SigAction::empty(),
            customed: false,
        }
    }
    pub fn from_act(signo: usize, act: SigAction) -> Self {
        if act.sa_handler == SIG_DFL {
            KSigAction::new(signo, false)
        } else if act.sa_handler == SIG_IGN {
            KSigAction::ignore()
        } else {
            let customed = act.sa_handler != exit_current_and_run_next as usize;
            Self { act: act, customed }
        }
    }
    pub fn get_handle(&self) -> usize {
        self.act.sa_handler
    }
}

