impl SignalFlags {
    pub fn default_op(&self) -> SigOp {
        let terminate_signals = SignalFlags::SIGHUP
            | SignalFlags::SIGINT
            | SignalFlags::SIGKILL
            | SignalFlags::SIGUSR1
            | SignalFlags::SIGUSR2
            | SignalFlags::SIGPIPE
            | SignalFlags::SIGALRM
            | SignalFlags::SIGTERM
            | SignalFlags::SIGSTKFLT
            | SignalFlags::SIGVTALRM
            | SignalFlags::SIGPROF
            | SignalFlags::SIGIO
            | SignalFlags::SIGPWR;
        let dump_signals = SignalFlags::SIGQUIT
            | SignalFlags::SIGILL
            | SignalFlags::SIGTRAP
            | SignalFlags::SIGABRT
            | SignalFlags::SIGBUS
            | SignalFlags::SIGFPE
            | SignalFlags::SIGSEGV
            | SignalFlags::SIGXCPU
            | SignalFlags::SIGXFSZ
            | SignalFlags::SIGSYS;
        let ignore_signals = SignalFlags::SIGCHLD | SignalFlags::SIGURG | SignalFlags::SIGWINCH;
        let stop_signals = SignalFlags::SIGSTOP
            | SignalFlags::SIGTSTP
            | SignalFlags::SIGTTIN
            | SignalFlags::SIGTTOU;
        let continue_signals = SignalFlags::SIGCONT;
        if terminate_signals.contains(*self) {
            SigOp::Terminate
        } else if dump_signals.contains(*self) {
            SigOp::CoreDump
        } else if ignore_signals.contains(*self) || self.bits == 0 {
            SigOp::Ignore
        } else if stop_signals.contains(*self) {
            SigOp::Stop
        } else if continue_signals.contains(*self) {
            SigOp::Continue
        } else {
            // println!("[kernel] signal {:?}: undefined default operation", self);
            SigOp::Terminate
        }
    }
    pub fn from_sig(signo: usize) -> Self {
        SignalFlags::from_bits(1 << signo).unwrap()
    }

    pub fn check_error(&self) -> Option<(i32, &'static str)> {
        if self.contains(Self::SIGINT) {
            Some((-(SIGINT as i32), "Killed, SIGINT=2"))
        } else if self.contains(Self::SIGILL) {
            Some((-(SIGILL as i32), "Illegal Instruction, SIGILL=4"))
        } else if self.contains(Self::SIGABRT) {
            Some((-(SIGABRT as i32), "Aborted, SIGABRT=6"))
        } else if self.contains(Self::SIGFPE) {
            Some((-(SIGFPE as i32), "Erroneous Arithmetic Operation, SIGFPE=8"))
        } else if self.contains(Self::SIGKILL) {
            Some((-(SIGKILL as i32), "Killed, SIGKILL=9"))
        } else if self.contains(Self::SIGSEGV) {
            Some((-(SIGSEGV as i32), "Segmentation Fault, SIGSEGV=11"))
        } else {
            //println!("[K] signalflags check_error  {:?}", self);
            None
        }
    }
}

