//! Kernel trap and interrupt handling
pub mod interrupts;
use crate::config::TIMER_IRQ;
use crate::signal::SignalFlags;
use crate::task;
use crate::{
    syscall::syscall,
    task::{
        check_signals_error_of_current, current_add_signal, current_task,
        exit_current_and_run_next, handle_signals, suspend_current_and_run_next,
    },
    utils::SysErrNo,
};
use interrupts::inc_irq_count;
use log::*;
use polyhal::VirtAddr;
use polyhal_trap::{
    trap::TrapType::{self, *},
    trapframe::{TrapFrame, TrapFrameArgs},
};

/// kernel interrupt handler, moved from main.rs
#[polyhal::arch_interrupt]
pub fn kernel_interrupt(ctx: &mut TrapFrame, trap_type: TrapType) {
    current_task()
        .unwrap()
        .inner_exclusive_access()
        .time_data
        .update_stime();
    match trap_type {
        Breakpoint => return,
        Irq(irq_vector) => {
            let irq_num = irq_vector.irq_num();
            debug!("[kernel] IRQ: {} (vector: {:?})", irq_num, irq_vector);
            inc_irq_count(irq_num);
            ctx[TrapFrameArgs::RET] = 0; // 清除返回值
        }
        SysCall => {
            ctx.syscall_ok();
            let args = ctx.args();
            let result = syscall(
                ctx[TrapFrameArgs::SYSCALL],
                [args[0], args[1], args[2], args[3], args[4], args[5]],
            );
            match result {
                Ok(val) => {
                    ctx[TrapFrameArgs::RET] = val;
                }
                Err(errno) => {
                    let err_str = errno.str();
                    error!(
                        "[syscall error] {} syscall number:{} (errno = {:?})",
                        err_str,
                        ctx[TrapFrameArgs::SYSCALL],
                        errno
                    );
                    ctx[TrapFrameArgs::RET] = -(errno as isize) as usize;
                }
            }
            inc_irq_count(TIMER_IRQ);
        }
        StorePageFault(_paddr) | LoadPageFault(_paddr) => {
            // match trap_type {
            //     StorePageFault(_) => warn!(
            //         "[kernel] StorePageFault occurred at {:#x}, pid = {}",
            //         _paddr,
            //         current_task().unwrap().getpid()
            //     ),
            //     LoadPageFault(_) => warn!("[kernel] LoadPageFault occurred at {:#x}", _paddr),
            //     _ => {}
            // }
            let mut ok;
            {
                let task = current_task().unwrap();
                let task_inner = task.inner_exclusive_access();
                let fault_vaddr = VirtAddr::new(_paddr).floor();
                ok = task_inner
                    .memory_set
                    .lazy_page_fault(fault_vaddr, trap_type);
                if !ok {
                    ok = task_inner.memory_set.cow_page_fault(fault_vaddr, trap_type);
                }
            }
            if !ok {
                warn!(
                    "[kernel] bad addr = {:#x}, bad instruction = {:#x}, kernel killed it.",
                    _paddr,
                    ctx[TrapFrameArgs::SEPC],
                );
                exit_current_and_run_next(-2);
            }
        }
        InstructionPageFault(_paddr) => {
            warn!("[kernel] InstructionPageFault occurred at {:#x}", _paddr);
            exit_current_and_run_next(-2);
            current_add_signal(SignalFlags::SIGSEGV);
        }
        IllegalInstruction(_) => {
            warn!(
                "[kernel] IllegalInstruction occurred at {:#x}",
                ctx[TrapFrameArgs::SEPC]
            );
            current_add_signal(SignalFlags::SIGILL);
        }
        Timer => {
            inc_irq_count(TIMER_IRQ);
            suspend_current_and_run_next();
        }
        _ => {
            warn!("unsuspended trap type: {:?}", trap_type);
        }
    }
    handle_signals();
    if let Some((errno, msg)) = check_signals_error_of_current() {
        error!("[trap_handler] Signal error: {}", msg);
        exit_current_and_run_next(errno);
    }
    current_task()
        .unwrap()
        .inner_exclusive_access()
        .time_data
        .update_stime();
}
