}

impl Tms {
    pub fn new(time_data: &TimeData) -> Self {
        Self {
            user_time: time_data.user_time,
            system_time: time_data.system_time,
            child_user_time: time_data.child_user_time,
            child_system_time: time_data.child_system_time,
        }
    }
    pub fn as_bytes(&self) -> &[u8] {
        let size = core::mem::size_of::<Self>();
        unsafe { core::slice::from_raw_parts(self as *const _ as usize as *const u8, size) }
    }
}

pub struct TimeData {
    pub user_time: isize,
    pub system_time: isize,
    pub child_user_time: isize,
    pub child_system_time: isize,
    pub last_time: isize,
}

impl TimeData {
    pub fn new() -> Self {
        let now_time = (get_time_ms()) as isize;
        Self {
            user_time: 0,
            system_time: 0,
            child_user_time: 0,
            child_system_time: 0,
            last_time: now_time,
        }
    }
    pub fn update_utime(&mut self) {
        let now = get_time() as isize;
        let duration = now - self.last_time;
        self.user_time += duration;
        self.last_time = now;
    }

    pub fn update_stime(&mut self) {
        let now = get_time() as isize;
        let duration = now - self.last_time;
        self.system_time += duration;
        self.last_time = now;
    }

    pub fn add_child_time(&mut self, child_time: &TimeData) {
        self.child_user_time += child_time.user_time + child_time.child_user_time;
        self.child_system_time += child_time.system_time + child_time.child_system_time;
    }

    pub fn clear(&mut self) {
        let now = get_time() as isize;
        self.last_time = now;
        self.user_time = 0;
        self.system_time = 0;
        self.child_user_time = 0;
        self.child_system_time = 0;
    }
}

/// Get the current time in ticks.
pub fn get_time() -> usize {
    Time::now().raw()
}

/// Get the current time in milliseconds.
pub fn get_time_ms() -> usize {
    Time::now().to_msec()
}

