pub fn sys_nanosleep(reqtime: *const u8, remtime: *const u8) -> SyscallRet {
    trace!(
        "[sys_nanosleep] Enter: reqtime=0x{:x}, remtime=0x{:x}",
        reqtime as usize,
        remtime as usize
    );
    let token = current_user_token();
    let req = translated_ref(token, reqtime as *const Timespec);

    let begin = get_time_ms();
    let waittime = req.tv_sec * 1000 + req.tv_nsec / 1000000;
    debug!(
        "[sys_nanosleep] Sleep for {} ms ({}s + {}ns)",
        waittime, req.tv_sec, req.tv_nsec
    );

    loop {
        let now = get_time_ms();
        if now - begin >= waittime {
            break;
        }
        suspend_current_and_run_next();
    }

    trace!("[sys_nanosleep] Exit: sleep completed");
    Ok(0)
}

