    let begin = get_time_ms() * 1_000_000; // 转换为纳秒
    let endtime = if flags == TIME_ABSTIME {
        t.tv_sec
    } else {
        get_time_ms() / 1000 + t.tv_sec
    };
    loop {
        let now: usize = get_time_ms();
        if now - begin >= waittime {
            break;
        }
        suspend_current_and_run_next();
    }
    Ok(0)
}

