pub fn sys_uname(ptr: *mut u8) -> SyscallRet {
    trace!(
        "[sys_uname] Enter: ptr=0x{:x} (output pointer for UtsName)",
        ptr as usize
    );
    // 辅助函数：将字符串复制到固定大小的缓冲区
    fn copy_str_to_buf(s: &str) -> [u8; 65] {
        let mut buf = [0u8; 65];
        let bytes = s.as_bytes();
        let len = bytes.len().min(64); // 确保不超过64字节（留一个字节给null终止符）
        buf[..len].copy_from_slice(&bytes[..len]);
        buf
    }
    let uts = UtsName {
        sysname: copy_str_to_buf(OS_NAME),
        nodename: copy_str_to_buf(OS_NODENAME),
        release: copy_str_to_buf(OS_RELEASE),
        version: copy_str_to_buf(OS_VERSION),
        machine: copy_str_to_buf(OS_MACHINE),
        domainname: copy_str_to_buf(OS_DOMAINNAME),
    };

    let token = current_user_token();

    let mut utsbuff = UserBuffer::new(translated_byte_buffer(
        &token,
        ptr,
        core::mem::size_of::<UtsName>(),
    ));
    utsbuff.write(uts.as_bytes());
    debug!("[sys_uname] Returned system information");
    Ok(0)
}

pub fn sys_getrusage(who: isize, rusage: *mut u8) -> SyscallRet {
    trace!(
        "[sys_getrusage] Enter: who={}, rusage=0x{:x} (output pointer for RUsage)",
        who,
        rusage as usize
    );
    // GETRUSAGECOUNT.fetch_add(1, Ordering::Relaxed);
    // if GETRUSAGECOUNT.load(Ordering::Relaxed) % 100 == 0 {
    //     println!(
    //         "[sys_getrusage] Called {} times",
    //         GETRUSAGECOUNT.load(Ordering::Relaxed)
    //     );
    // }
    const RUSAGESELF: isize = 0;
    const RUSAGECHILDREN: isize = -1;

    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();

    match who {
        RUSAGESELF => {
            // 获取当前任务的资源使用情况
            let usage = Rusage::new_from_ms(
                inner.time_data.user_time as usize,
                inner.time_data.system_time as usize,
            );
            put_data(token, rusage as *mut Rusage, usage);
            Ok(0)
        }
        RUSAGECHILDREN => {
            // 获取子任务的资源使用情况
            let usage = Rusage::new_from_ms(
                inner.time_data.child_user_time as usize,
                inner.time_data.child_system_time as usize,
            );
            put_data(token, rusage as *mut Rusage, usage);
            Ok(0)
        }
        _ => {
            warn!("[sys_getrusage] Invalid 'who' value: {}", who);
            return Err(SysErrNo::EINVAL);
        }
    }
}

