        let mut len = name.len() + 19;
        let align = 8 - len % 8;
        len += align;
        for _ in 0..align {
            name.push('\0');
        }
        Self {
            d_ino: ino as usize,
            d_off: off as isize,
            d_reclen: len as u16,
            d_type: dtype,
            d_name: {
                let mut tmp: [u8; 256] = [0; 256];
                tmp[..name.len()].copy_from_slice(name.as_bytes());
                tmp
            },
        }
