    pub st_blocks: isize,     // 分配的 512B 块数
    pub st_atime: isize,      // 上次访问时间
    pub st_atime_nsec: usize, // 上次访问时间（纳秒精度）
    pub st_mtime: isize,      // 上次修改时间
    pub st_mtime_nsec: usize, // 上次修改时间（纳秒精度）
    pub st_ctime: isize,      // 上次状态变化的时间
    pub st_ctime_nsec: usize, // 上次状态变化的时间（纳秒精度）
    pub __unused: [u32; 2],
}

impl Kstat {
    pub fn new() -> Self {
        Self {
            st_dev: 0,
            st_ino: 0,
            st_mode: 0,
            st_nlink: 0,
            st_uid: 0,
            st_gid: 0,
            st_rdev: 0,
            __pad: 0,
            st_size: 0,
            st_blksize: 0,
            __pad2: 0,
            st_blocks: 0,
            st_atime: 0,
            st_atime_nsec: 0,
            st_mtime: 0,
            st_mtime_nsec: 0,
            st_ctime: 0,
            st_ctime_nsec: 0,
            __unused: [0; 2],
        }
    }

    pub fn init(&mut self, st_size: isize, st_blksize: i32, st_blocks: isize) {
        self.st_nlink = 1;
        self.st_size = st_size;
        self.st_blksize = st_blksize;
        self.st_blocks = st_blocks;
    }

    pub fn as_bytes(&self) -> &[u8] {
        let size = core::mem::size_of::<Self>();
        unsafe { core::slice::from_raw_parts(self as *const _ as usize as *const u8, size) }
    }
}

#[repr(C)]
#[derive(Debug, Default)]
pub struct StatxTimestamp {
    pub tv_sec: i64,
    pub tv_nsec: u32,
    pad: i32,
}

#[repr(C)]
#[derive(Debug, Default)]
pub struct Statx {
    pub stx_mask: u32,
    pub stx_blksize: u32,
    pub stx_attributes: u64,
    pub stx_nlink: u32,
    pub stx_uid: u32,
    pub stx_gid: u32,
    pub stx_mode: u16,
    pad1: u16,
    pub stx_ino: u64,
    pub stx_size: u64,
    pub stx_blocks: u64,
    pub stx_attributes_mask: u64,
    pub stx_atime: StatxTimestamp,
    pub stx_btime: StatxTimestamp,
    pub stx_ctime: StatxTimestamp,
    pub stx_mtime: StatxTimestamp,
    pub stx_rdev_major: u32,
    pub stx_rdev_minor: u32,
    pub stx_dev_major: u32,
    pub stx_dev_minor: u32,
    spare: [u64; 14],
}

impl Statx {
    pub fn new() -> Self {
        Self::default()
    }
    pub fn as_bytes(&self) -> &[u8] {
        let size = core::mem::size_of::<Self>();
        unsafe { core::slice::from_raw_parts(self as *const _ as usize as *const u8, size) }
    }
}

impl From<Kstat> for Statx {
    fn from(kstat: Kstat) -> Self {
        let mut statx = Statx::new();
        statx.stx_mask = 0xffffffff; // TODO: set mask based on available fields
        statx.stx_blksize = kstat.st_blksize as u32;
        statx.stx_nlink = kstat.st_nlink;
        statx.stx_uid = kstat.st_uid;
        statx.stx_gid = kstat.st_gid;
        statx.stx_mode = kstat.st_mode as u16;
        statx.stx_ino = kstat.st_ino as u64;
        statx.stx_size = kstat.st_size as u64;
        statx.stx_blocks = kstat.st_blocks as u64;
        statx.stx_atime = StatxTimestamp {
            tv_sec: kstat.st_atime as i64,
            tv_nsec: kstat.st_atime_nsec as u32,
            pad: 0,
        };
        statx.stx_mtime = StatxTimestamp {
            tv_sec: kstat.st_mtime as i64,
            tv_nsec: kstat.st_mtime_nsec as u32,
            pad: 0,
        };
        statx.stx_ctime = StatxTimestamp {
            tv_sec: kstat.st_ctime as i64,
            tv_nsec: kstat.st_ctime_nsec as u32,
            pad: 0,
        };
        // Kstat does not have btime, so we leave it as default (0)
        statx.stx_btime = StatxTimestamp::default();

        // Assuming major and minor are packed in st_dev/st_rdev
        // This is a common convention but might need adjustment
        statx.stx_dev_major = ((kstat.st_dev >> 8) & 0xff) as u32;
        statx.stx_dev_minor = (kstat.st_dev & 0xff) as u32;
        statx.stx_rdev_major = ((kstat.st_rdev >> 8) & 0xff) as u32;
        statx.stx_rdev_minor = (kstat.st_rdev & 0xff) as u32;

        statx
    }
}

